# scripts/governance_metrics.py — collect PR cycle times
from datetime import datetime, timezone
from github import Github
import os, json

def collect_pr_metrics(repo_name: str, since_days: int = 30) -> list[dict]:
    g = Github(os.environ["GH_TOKEN"])
    repo = g.get_repo(repo_name)
    metrics = []

    for pr in repo.get_pulls(state="closed", sort="updated", direction="desc"):
        if not any(f.filename.startswith("src/prompts/") for f in pr.get_files()):
            continue

        opened  = pr.created_at
        ci_pass = None
        first_review = None
        merged  = pr.merged_at

        for commit in pr.get_commits():
            for status in commit.get_check_runs():
                if status.conclusion == "success" and ci_pass is None:
                    ci_pass = status.completed_at

        comments = list(pr.get_review_comments()) + list(pr.get_issue_comments())
        if comments:
            first_review = min(c.created_at for c in comments)

        if merged:
            metrics.append({
                "pr": pr.number,
                "title": pr.title,
                "open_to_ci_min": (ci_pass - opened).total_seconds() / 60 if ci_pass else None,
                "ci_to_review_hrs": (first_review - ci_pass).total_seconds() / 3600 if ci_pass and first_review else None,
                "open_to_merge_hrs": (merged - opened).total_seconds() / 3600,
                "is_hotfix": "[HOTFIX]" in pr.title,
            })

    return metrics
